+/// Helper: calculate Q2_K size for a given number of elements
+/// Q2_K block: 84 bytes for 256 values
+pub fn q2kBlockBytes(num_elements: usize) usize {
+    const num_blocks = (num_elements + 255) / 256; // ceil division
+    return num_blocks * 84;
