+    /// Calculate Q2_K offsets for a given config
+    pub fn init(config: QwenConfig) Q2KLayerOffsets {
+        var offset: usize = 0;
+
+        // Non-quantized tensors first (BF16)
+        const input_layernorm = offset;
+        offset += config.hidden_size * 2;
+
+        const q_bias = offset;
+        offset += config.hidden_size * 2;
+
+        const k_bias = offset;
+        offset += config.kv_dim * 2;
+
+        const v_bias = offset;
+        offset += config.kv_dim * 2;
+
+        const post_attn_layernorm = offset;
+        offset += config.hidden_size * 2;
+
+        // Align to 64 bytes for Q2_K blocks (helps CPU cache alignment)
+        offset = std.mem.alignForward(usize, offset, 64);
+
+        // Q2_K quantized tensors
+        const q_elements = @as(usize, config.hidden_size) * config.hidden_size;
+        const q_proj = offset;
+        const q_proj_bytes = q2kBlockBytes(q_elements);
+        const q_proj_blocks = (q_elements + 255) / 256;
+        offset += q_proj_bytes;
