+        const k_elements = @as(usize, config.hidden_size) * config.kv_dim;
+        const k_proj = offset;
+        const k_proj_bytes = q2kBlockBytes(k_elements);
+        const k_proj_blocks = (k_elements + 255) / 256;
+        offset += k_proj_bytes;
+
+        const v_elements = @as(usize, config.hidden_size) * config.kv_dim;
+        const v_proj = offset;
+        const v_proj_bytes = q2kBlockBytes(v_elements);
+        const v_proj_blocks = (v_elements + 255) / 256;
+        offset += v_proj_bytes;
+
+        const o_elements = @as(usize, config.hidden_size) * config.hidden_size;
+        const o_proj = offset;
+        const o_proj_bytes = q2kBlockBytes(o_elements);
+        const o_proj_blocks = (o_elements + 255) / 256;
+        offset += o_proj_bytes;
+
+        const gate_elements = @as(usize, config.hidden_size) * config.intermediate_size;
+        const gate_proj = offset;
+        const gate_proj_bytes = q2kBlockBytes(gate_elements);
+        const gate_proj_blocks = (gate_elements + 255) / 256;
+        offset += gate_proj_bytes;
+
+        const up_elements = @as(usize, config.hidden_size) * config.intermediate_size;
+        const up_proj = offset;
+        const up_proj_bytes = q2kBlockBytes(up_elements);
+        const up_proj_blocks = (up_elements + 255) / 256;
+        offset += up_proj_bytes;
+
+        const down_elements = @as(usize, config.intermediate_size) * config.hidden_size;
+        const down_proj = offset;
+        const down_proj_bytes = q2kBlockBytes(down_elements);
+        const down_proj_blocks = (down_elements + 255) / 256;
+        _ = offset + down_proj_bytes;
+
+        return Q2KLayerOffsets{
+            .input_layernorm = input_layernorm,
+            .q_bias = q_bias,
+            .k_bias = k_bias,
+            .v_bias = v_bias,
