+
+        // Helper to copy a single tensor
+        const copyTensor = struct {
+            fn copy(loader: *gguf.GGUFLoader, name: []const u8, dst: []u8, offset: usize, max_size: usize) void {
+                if (loader.getRawQ2KSlice(name)) |src| {
+                    const copy_size = @min(src.len, max_size);
+                    @memcpy(dst[offset..][0..copy_size], src[0..copy_size]);
+                }
+            }
+        }.copy;
+
